output.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?team ?teamLabel ?gm ?gmLabel WHERE {
  ?division wdt:P361 wd:Q318389 .
  ?team wdt:P1416 ?division .
  ?team wdt:P4171 ?gm .
  OPTIONAL {
    ?team rdfs:label ?teamLabel
    FILTER(lang(?teamLabel) = "en")
    .
  }
  OPTIONAL {
    ?gm rdfs:label ?gmLabel
    FILTER(lang(?gmLabel) = "en")
    .
  }
}
